protected QueryBuildDataSource joinInventDim(
    QueryBuildDataSource    _qbdsParent,
    InventDimParm           _inventDimParm)
{
    QueryBuildDataSource qbdsInventDim;

    qbdsInventDim = next joinInventDim(_qbdsParent, _inventDimParm);
    _qbdsParent.addGroupByField(fieldNum(InventValueReportView, InventTransId));
    return qbdsInventDim;
}

protected InventValueReportTmpLine findReportLine(
    InventValueReportLineType   _lineType,
    InventTable                 _inventTable,
    InventItemGroupItem         _inventItemGroupItem,
    InventValueReportView       _inventView,
    InventDim                   _inventDim)
{
    InventValueReportTmpLine    tmpReportLine;

    tmpReportLine = next findReportLine(_lineType, _inventTable, _inventItemGroupItem, _inventView, _inventDim);
    tmpReportLine.InventTransId = _inventView.InventTransId;

    return tmpReportLine;
}
